import React, { useState, useRef, useEffect, useCallback } from "react";
import { Link } from "react-router-dom";

const ProductGroup = ({
  titlePrefix,
  icon,
  titleSuffix,
  colorClass,
  products = [],
}) => {
  const scrollRef = useRef(null);
  const isPausedRef = useRef(false);

  const displayProducts = products.length > 0 ? products : [];

  // Adjusted auto-scroll: increment by 1/3 of the container width to show exactly 3 cards
  useEffect(() => {
    if (displayProducts.length < 3) return;
    const timer = setInterval(() => {
      if (isPausedRef.current || !scrollRef.current) return;
      const el = scrollRef.current;
      const step = el.clientWidth / 3;
      const maxScroll = el.scrollWidth - el.clientWidth;
      if (el.scrollLeft >= maxScroll - 10) {
        el.scrollTo({ left: 0, behavior: "smooth" });
      } else {
        el.scrollBy({ left: step, behavior: "smooth" });
      }
    }, 4000);
    return () => clearInterval(timer);
  }, [displayProducts.length]);

  if (displayProducts.length === 0) return null;

  const scroll = (dir) => {
    if (scrollRef.current) {
      const step = scrollRef.current.clientWidth / 3;
      scrollRef.current.scrollBy({
        left: dir * step,
        behavior: "smooth",
      });
    }
  };

  return (
    <div
      onMouseEnter={() => {
        isPausedRef.current = true;
      }}
      onMouseLeave={() => {
        isPausedRef.current = false;
      }}
      style={{
        background: "#ffffff",
        borderRadius: "16px",
        padding: "18px 18px 16px",
        boxShadow: "0 2px 16px rgba(0,0,0,0.07)",
        border: "1px solid #f0f0f0",
        display: "flex",
        flexDirection: "column",
        height: "100%", // Ensure equal height for both blocks
      }}
    >
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: "14px",
          paddingBottom: "12px",
          borderBottom: "1px solid #f5f5f5",
        }}
      >
        <h2
          style={{
            fontSize: "15px",
            fontWeight: "700",
            color: "#1a1a2e",
            margin: 0,
            display: "flex",
            alignItems: "center",
            gap: "5px",
            letterSpacing: "0.2px",
          }}
        >
          {titlePrefix}{" "}
          <span
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "4px",
              fontWeight: "800",
            }}
            className={colorClass}
          >
            <span style={{ fontSize: "13px" }}>{icon}</span>
            {titleSuffix}
          </span>
        </h2>

        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          {/* Scroll arrows */}
          {[
            { dir: -1, label: "←" },
            { dir: 1, label: "→" },
          ].map(({ dir, label }) => (
            <button
              key={dir}
              onClick={() => scroll(dir)}
              className="group-scroll-arrow"
              style={{
                width: "28px",
                height: "28px",
                borderRadius: "50%",
                border: "1px solid #e5e7eb",
                background: "#fff",
                cursor: "pointer",
                fontSize: "12px",
                color: "#6b7280",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: 0,
                transition: "all 0.2s",
                lineHeight: 1,
              }}
            >
              {label}
            </button>
          ))}

          <Link
            to="/shop"
            style={{
              fontSize: "11px",
              color: "#9ca3af",
              textDecoration: "none",
              fontWeight: "500",
              padding: "3px 8px",
              border: "1px solid #e5e7eb",
              borderRadius: "20px",
              transition: "all 0.2s ease",
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.color = "#374151";
              e.currentTarget.style.borderColor = "#9ca3af";
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.color = "#9ca3af";
              e.currentTarget.style.borderColor = "#e5e7eb";
            }}
          >
            See all
          </Link>
        </div>
      </div>

       <style>{`
        .product-scroll-item {
          flex: 0 0 calc(33.333% - 11px);
          max-width: calc(33.333% - 11px);
        }
        .group-scroll-arrow:hover {
          background: #f3f4f6 !important;
          border-color: #9ca3af !important;
        }
        @media (max-width: 900px) {
          .product-scroll-item {
            flex: 0 0 calc(46% - 8px) !important;
            max-width: calc(46% - 8px) !important;
          }
        }
        @media (max-width: 500px) {
          .product-scroll-item {
            flex: 0 0 calc(48% - 6px) !important;
            max-width: calc(48% - 6px) !important;
          }
        }
      `}</style>

      {/* Horizontal Scroll Slider */}
      <div style={{ position: "relative", overflow: "hidden" }}>
        <div
          ref={scrollRef}
          style={{
            display: "flex",
            gap: "16px",
            overflowX: "scroll",
            overflowY: "visible",
            paddingBottom: "12px",
            scrollbarWidth: "none",
            msOverflowStyle: "none",
            scrollSnapType: "x mandatory",
            WebkitOverflowScrolling: "touch",
          }}
          className="product-scroll-container hide-scrollbar"
        >
          {displayProducts.map((p, idx) => {
            const imageUrl =
              p?.colors?.[0]?.images?.[0]?.secure_url ||
              "/images/default-product.png";
            const key = p._id + idx;

            return (
              <div
                key={key}
                className="product-scroll-item"
                style={{
                  background: "#fff",
                  borderRadius: "16px",
                  padding: "12px",
                  border: "1px solid #f1f5f9",
                  display: "flex",
                  flexDirection: "column",
                  transition: "all 0.3s ease",
                  scrollSnapAlign: "start",
                  position: "relative",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.03)",
                }}
              >
                {/* Image Wrap */}
                <div
                  style={{
                    width: "100%",
                    aspectRatio: "1/1",
                    borderRadius: "12px",
                    overflow: "hidden",
                    background: "#fdfdfd",
                    position: "relative",
                    marginBottom: "12px",
                  }}
                >
                  {/* Status Badge */}
                  <div
                    style={{
                      position: "absolute",
                      top: 8,
                      left: 8,
                      background: p.quantity > 0 ? "#14b8a6" : "#ef4444",
                      color: "#fff",
                      fontSize: "0.6rem",
                      fontWeight: 900,
                      padding: "4px 8px",
                      borderRadius: "100px",
                      zIndex: 10,
                      textTransform: "uppercase",
                      letterSpacing: "0.05em",
                      boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
                    }}
                  >
                    {p.quantity > 0 ? "Flash Offer" : "Soon"}
                  </div>
                  
                  <Link to={`/productdetails/${p._id}`} style={{ display: "block", height: "100%" }}>
                    <img
                      src={imageUrl}
                      alt={p.title}
                      style={{
                        width: "100%",
                        height: "100%",
                        objectFit: "contain",
                        transition: "transform 0.5s",
                      }}
                      onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.08)")}
                      onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
                    />
                  </Link>
                </div>

                {/* Content */}
                <span style={{ 
                  fontSize: "9px", 
                  fontWeight: 900, 
                  color: "#14b8a6", 
                  textTransform: "uppercase",
                  letterSpacing: "0.05em",
                  marginBottom: "4px"
                }}>
                  {p.category}
                </span>

                <h4 style={{
                  fontSize: "12px",
                  fontWeight: "700",
                  color: "#1a1a2e",
                  margin: "0 0 10px",
                  display: "-webkit-box",
                  WebkitLineClamp: 2,
                  WebkitBoxOrient: "vertical",
                  overflow: "hidden",
                  lineHeight: "1.4",
                  height: "34px", // Ensure consistent title height
                  textTransform: "uppercase"
                }}>
                  {p.title}
                </h4>

                {/* Footer with Price and View Button */}
                <div style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  marginTop: "auto",
                  paddingTop: "10px",
                  borderTop: "1px solid #f8fafc"
                }}>
                  <div style={{ display: "flex", flexDirection: "column" }}>
                    <span style={{ fontSize: "12px", fontWeight: "900", color: "#1a1a2e" }}>
                      {p.price?.toLocaleString()}
                    </span>
                    <span style={{ fontSize: "7px", fontWeight: "900", color: "#94a3b8", textTransform: "uppercase" }}>
                      ETB Currency
                    </span>
                  </div>

                  <Link
                    to={`/productdetails/${p._id}`}
                    style={{
                      background: "#f8fafc",
                      border: "1px solid #e2e8f0",
                      color: "#64748b",
                      fontSize: "0.65rem",
                      fontWeight: 800,
                      padding: "6px 10px",
                      borderRadius: "8px",
                      textDecoration: "none",
                      textTransform: "uppercase",
                      transition: "all 0.2s",
                    }}
                    onMouseOver={(e) => {
                      e.currentTarget.style.background = "#14b8a6";
                      e.currentTarget.style.color = "#fff";
                      e.currentTarget.style.borderColor = "#14b8a6";
                    }}
                    onMouseOut={(e) => {
                      e.currentTarget.style.background = "#f8fafc";
                      e.currentTarget.style.color = "#64748b";
                      e.currentTarget.style.borderColor = "#e2e8f0";
                    }}
                  >
                    View
                  </Link>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default ProductGroup;
