import React, { useMemo } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { Swiper, SwiperSlide } from "swiper/react";
import { Navigation, Autoplay } from "swiper/modules";
import "swiper/css";
import "swiper/css/navigation";

const ProductTagSection = ({
  tag,
  title,
  subtitle,
  icon,
  products,
  highlightColor = "text-teal-600",
}) => {
  const { isLoading } = useSelector((state) => state.product);
  const filteredProducts = products || [];

  if (isLoading || filteredProducts.length === 0) return null;

  // Unique ID for swiper navigation buttons based on title - ensuring valid CSS selector characters
  const safeId = title.toLowerCase().replace(/[^a-z0-9]/g, "-");

  return (
    <section className="py-8 md:py-16 bg-white border-b border-gray-50 overflow-hidden">
        <style>{`
            @media (max-width: 768px) {
                .tag-section-header { margin-bottom: 24px !important; }
                .tag-section-title { font-size: 1.5rem !important; }
                .tag-section-card-img { height: 160px !important; }
            }
        `}</style>
      <div className="w-full max-w-[1400px] mx-auto px-4 lg:px-12 text-center relative z-10">
        {/* Centered Header Section */}
        <div className="flex flex-col items-center text-center mb-6 md:mb-12 relative tag-section-header">
          <div className="inline-flex items-center gap-2 mb-3 bg-teal-50/50 px-4 py-1.5 rounded-full border border-teal-100/50">
            <span
              className={`${highlightColor} text-[10px] font-black uppercase tracking-[0.4em]`}
            >
              {subtitle || "Current Event"}
            </span>
          </div>

          <h2 className="text-2xl md:text-4xl font-black text-gray-900 uppercase tracking-tighter flex items-center justify-center gap-4 tag-section-title">
            <span className="w-8 h-[3px] bg-teal-500/20 hidden md:block rounded-full"></span>
            {title}
            <span
              className={
                tag?.toLowerCase().includes("flash") ? "animate-pulse" : ""
              }
            >
              {icon}
            </span>
            <span className="w-8 h-[3px] bg-teal-500/20 hidden md:block rounded-full"></span>
          </h2>

          {/* Subtle underline decoration */}
          <div className="mt-4 flex gap-1">
            <div className="w-12 h-1 bg-teal-500 rounded-full"></div>
            <div className="w-2 h-1 bg-[#facc15] rounded-full"></div>
            <div className="w-2 h-1 bg-teal-600 rounded-full"></div>
          </div>
        </div>

        {/* Products Slider */}
        <div className="relative group">
          <Swiper
            modules={[Navigation, Autoplay]}
            spaceBetween={20}
            slidesPerView={1.5}
            navigation={{
              nextEl: `.swiper-button-next-${safeId}`,
              prevEl: `.swiper-button-prev-${safeId}`,
            }}
            autoplay={{ delay: 5000, disableOnInteraction: false }}
            breakpoints={{
              320: { slidesPerView: 2.1, spaceBetween: 10 },
              640: { slidesPerView: 3.2, spaceBetween: 16 },
              1024: { slidesPerView: 4.2, spaceBetween: 20 },
            }}
            className="pb-4"
          >
            {filteredProducts.map((p) => {
              const imgSrc =
                p.colors?.[0]?.images?.[0]?.secure_url ||
                p.images?.[0]?.secure_url;
              return (
                <SwiperSlide key={p._id}>
                  <Link
                    to={`/productdetails/${p._id}`}
                    className="bg-gray-50 rounded-[30px] overflow-hidden border border-gray-100 group/card hover:bg-white hover:shadow-2xl transition-all duration-500 h-full flex flex-col"
                  >
                    <div className="h-[200px] w-full overflow-hidden relative flex items-center justify-center bg-[#f8fafc]">
                      <img
                        src={imgSrc}
                        alt={p.title}
                        className="w-full h-full object-cover transition-transform duration-700 group-hover/card:scale-110 tag-section-card-img"
                      />
                      {/* Price Badge */}
                      <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-3 py-1.5 rounded-full shadow-sm">
                        <span className="text-teal-700 font-black text-xs">
                          ETB {p.price?.toLocaleString()}
                        </span>
                      </div>

                      {/* Sale Overlay */}
                      <div className="absolute inset-x-0 bottom-0 p-4 bg-gradient-to-t from-white/90 via-white/40 to-transparent translate-y-full group-hover/card:translate-y-0 transition-transform duration-500 backdrop-blur-sm">
                        <button className="w-full bg-[#0d9488] text-white text-[10px] font-black uppercase py-3 rounded-2xl shadow-xl shadow-teal-900/10 hover:bg-[#115e59] transition-colors">
                          View Details
                        </button>
                      </div>
                    </div>

                    <div className="p-3 md:p-5 flex flex-col flex-grow text-left">
                      <span className="text-teal-600 text-[9px] font-black uppercase tracking-tighter mb-1 opacity-70">
                        Code: {p._id.slice(-5).toUpperCase()}
                      </span>
                      <h3 className="text-gray-900 font-bold text-sm mb-2 line-clamp-1 group-hover/card:text-teal-600 transition-colors uppercase">
                        {p.title}
                      </h3>
                      <div className="flex items-center gap-1 mt-auto">
                        <div className="flex text-[#facc15]">
                          {[...Array(5)].map((_, i) => (
                            <svg
                              key={i}
                              className="w-3 h-3 fill-current"
                              viewBox="0 0 20 20"
                            >
                              <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                            </svg>
                          ))}
                        </div>
                        <span className="text-[10px] text-gray-400 font-bold">
                          (24)
                        </span>
                      </div>
                    </div>
                  </Link>
                </SwiperSlide>
              );
            })}
          </Swiper>

          {/* Custom Arrows */}
          <button
            className={`swiper-button-prev-${safeId} absolute -left-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 bg-white rounded-full shadow-xl flex items-center justify-center text-teal-600 border border-teal-50 hover:bg-teal-600 hover:text-white transition-all opacity-0 group-hover:opacity-100 -translate-x-4 group-hover:translate-x-0`}
          >
            <svg
              className="w-6 h-6 rotate-180"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="3"
                d="M9 5l7 7-7 7"
              />
            </svg>
          </button>
          <button
            className={`swiper-button-next-${safeId} absolute -right-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 bg-white rounded-full shadow-xl flex items-center justify-center text-teal-600 border border-teal-50 hover:bg-teal-600 hover:text-white transition-all opacity-0 group-hover:opacity-100 translate-x-4 group-hover:translate-x-0`}
          >
            <svg
              className="w-6 h-6"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="3"
                d="M9 5l7 7-7 7"
              />
            </svg>
          </button>
        </div>
      </div>
    </section>
  );
};

export default ProductTagSection;
