import React, { useMemo } from "react";
import { useSelector } from "react-redux";
import ProductGroup from "./ProductGroup";
import { FaFire, FaChartLine } from "react-icons/fa";

const ProductGroupsContainer = ({ deals, trends }) => {
  // Use passed props or fallback to empty arrays
  const group1Products = deals || [];
  const group2Products = trends || [];

  return (
    <section
      style={{
        width: "100%",
        background: "linear-gradient(180deg, #f8fafc 0%, #ffffff 100%)",
        padding: "20px 0",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: "1400px",
          margin: "0 auto",
          padding: "0 12px",
        }}
      >
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr", // Force equal parts
            gap: "24px",
            alignItems: "stretch",
          }}
          className="product-group-grid"
        >
          <div style={{ minWidth: 0 }}>
            <ProductGroup
              titlePrefix="Super"
              icon={<FaFire />}
              titleSuffix="Deals"
              colorClass="text-rose-500"
              products={group1Products}
            />
          </div>
          <div style={{ minWidth: 0 }}>
            <ProductGroup
              titlePrefix="Top"
              icon={<FaChartLine />}
              titleSuffix="Trends"
              colorClass="text-teal-500"
              products={group2Products}
            />
          </div>
        </div>
      </div>

      <style>{`
        @media (max-width: 1024px) {
          .product-group-grid {
            grid-template-columns: 1fr !important;
            gap: 16px !important;
          }
        }
      `}</style>
    </section>
  );
};

export default ProductGroupsContainer;
